import 'patch.dart';

class Profile {
  final String? displayName;
  final String? note;

  const Profile({required this.displayName, required this.note});
}

class ProfileStore {
  Profile _current;

  ProfileStore(this._current);

  Profile get current => _current;

  void apply(ProfilePatch patch) {
    _current = Profile(
      displayName: patch.displayName.value ?? _current.displayName,
      note: patch.note.value ?? _current.note,
    );
  }
}
